<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=htmlspecialchars($meta['titulo'],ENT_QUOTES,'UTF-8')?></title><link rel="stylesheet" href="<?=BASE_URL?>/public/css/admin.css"></head><body class="report-print-page"><header class="report-print-header"><img src="<?=BASE_URL?>/public/img/logo.png" alt="UTSC"><div><strong>Portal Web de Pagos UTSC</strong><h1><?=htmlspecialchars($meta['titulo'],ENT_QUOTES,'UTF-8')?></h1><p>Generado: <?=date('d/m/Y H:i')?> · Administrador: <?=htmlspecialchars($administrador,ENT_QUOTES,'UTF-8')?></p></div></header><section class="report-print-filters"><h2>Filtros aplicados</h2><p><?=htmlspecialchars(implode(' · ',array_filter(array_map(fn($k,$v)=>$v!==''?ucfirst($k).': '.$v:null,array_keys($filtros),$filtros)))?:'No aplicado',ENT_QUOTES,'UTF-8')?></p></section><div class="report-print-summary"><?php foreach($resumen as$k=>$v):?><span><?=htmlspecialchars(ucfirst(str_replace('_',' ',$k)),ENT_QUOTES,'UTF-8')?>: <strong><?=str_contains($k,'monto')?'$'.number_format((float)$v,2):number_format((float)$v)?></strong></span><?php endforeach;?></div><p>Número de registros: <?=count($registros)?></p><table class="report-print-table"><thead><tr><?php foreach($meta['columnas']as$h):?><th><?=htmlspecialchars($h,ENT_QUOTES,'UTF-8')?></th><?php endforeach;?></tr></thead><tbody><?php foreach($registros as$row):?><tr><?php foreach(array_keys($meta['columnas'])as$k):?><td><?=htmlspecialchars($this->valor($k,$row[$k]??''),ENT_QUOTES,'UTF-8')?></td><?php endforeach;?></tr><?php endforeach;?></tbody></table><div class="report-print-actions"><button onclick="window.print()">Imprimir / Guardar como PDF</button></div></body></html>
